components.codeTemplate:
ContentUnavailableView {
    Label("{title}", systemImage: "{systemImage}")
} description: {
    Text("{description}")
} actions: {
    if {hasAction} {
        Button("{actionTitle}") { /* recover */ }
            .buttonStyle(.borderedProminent)
    }
}
// Search preset: ContentUnavailableView.search(text: {searchText})

ProgressView(value: {value}, total: {total}) {
    Text("{label}")
} currentValueLabel: {
    if {showsCurrentValueLabel} {
        Text({value} / {total}, format: .percent)
    }
}
.progressViewStyle(.{style})
.tint({tint})
// Indeterminate: ProgressView("{label}")
// Timer: ProgressView(timerInterval: range, countsDown: {countsDown})

Gauge(value: {value}, in: {minValue}...{maxValue}) {
    Text("{label}")
} currentValueLabel: {
    if {showsCurrentValueLabel} { Text("\(Int({value}))") }
} minimumValueLabel: {
    if {showsBoundsLabels} { Text("\(Int({minValue}))") }
} maximumValueLabel: {
    if {showsBoundsLabels} { Text("\(Int({maxValue}))") }
}
.gaugeStyle(.{style})
.tint({tint})

CardView(item: placeholderItem)
    .redacted(reason: {isRedacted} ? .{reason} : [])
// Keep one control live:
//   Button("Retry") { }.unredacted()
// Read in a custom view:
//   @Environment(\.redactionReasons) private var reasons

Text("$\(balance, specifier: \"%.2f\")")
    .privacySensitive({sensitive})
// Preview obscured look:
//   .redacted(reason: {demoForcePrivacy} ? .privacy : [])
// React to capture:
//   @Environment(\.isSceneCaptured) private var isCaptured

@State private var trigger = 0

Button("Act") { trigger += 1 }
    .sensoryFeedback(.{feedback}, trigger: trigger)
// Impact: .sensoryFeedback(.impact(weight: .{impactWeight}, intensity: {impactIntensity}), trigger: trigger)
// Gated: .sensoryFeedback(.{feedback}, trigger: trigger) { old, new in new > old }

List {
    Label("Inbox", systemImage: "tray")
        .badge({count})
    Label("Drafts", systemImage: "doc")
        .badge("{label}")
}
.badgeProminence(.{prominence})
// Tab badge: Tab("Inbox", systemImage: "tray") { ... }.badge({count})

Image(systemName: "wifi")
    .symbolEffect(.{effect}, options: .{options}, value: triggerValue)
// Indefinite while active:
//   .symbolEffect(.pulse, isActive: {isActive})
// Remove inherited effects:
//   .symbolEffectsRemoved({effectsRemoved})

someView
    .alert("{title}", isPresented: ${isPresented}) {
        Button("Delete", role: .destructive) { }
        Button("Cancel", role: .cancel) { }
    } message: {
        Text("{message}")
    }

someView
    .confirmationDialog("{title}", isPresented: ${isPresented}, titleVisibility: .{titleVisibility}) {
        Button("Delete", role: .destructive) { }
        Button("Cancel", role: .cancel) { }
    } message: {
        Text("Optional context")
    }
